        "specialQualities": "Tremorsense 60 ft., plant",
        "saves": "Fort +18, Ref +11, Will +8",
        "abilities": "Str 24, Dex 17, Con 20, Int -, Wis 13, Cha 5",
        "skills": "Wilderness Lore +21 Feat: Track",
