        "saves": "Fort +2, Ref +0, Will +0",
        "abilities": "Str 10, Dex 11, Con 10, Int -, Wis 10, Cha 8",
        "skills": "Listen +3, Spot +8",
        "feats": "",
        "climateTerrain": "Temperate and warm land 4 Solitary, pair, or swarm (3-10)",
